"use client";

import { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import Image from "next/image";
import { Check } from "lucide-react";
import { useWindowStore } from "@/stores/useWindowStore";

// ─── Constants & Types ───────────────────────────────────────────────────────

type SectionId = "intro" | "offer" | "awards" | "clients";

interface NavItem {
    id: SectionId;
    label: string;
}

const NAV_ITEMS: NavItem[] = [
    { id: "intro", label: "I'm Dzakwan" },
    { id: "offer", label: "What I Offer" },
    { id: "awards", label: "Awards & Press" },
    { id: "clients", label: "Clients" },
];

// ─── Main Component ──────────────────────────────────────────────────────────

export default function AboutApp() {
    const [activeSection, setActiveSection] = useState<SectionId>("intro");

    const windows = useWindowStore((s) => s.windows);
    const closeWindow = useWindowStore((s) => s.closeWindow);
    const minimizeWindow = useWindowStore((s) => s.minimizeWindow);
    const maximizeWindow = useWindowStore((s) => s.maximizeWindow);
    const restoreWindow = useWindowStore((s) => s.restoreWindow);

    const windowId = Object.keys(windows).find(id => windows[id]?.appId === "about") as any;
    const win = windowId ? windows[windowId] : null;

    if (!win) return null;

    return (
        <div className="h-full bg-white flex flex-row overflow-hidden font-sans select-none">
            {/* ── Sidebar ────────────────────────────────────────── */}
            <div className="w-[200px] shrink-0 bg-[#EFEBE6] border-r border-black/5 flex flex-col pt-4 px-3 pb-2 window-drag-handle cursor-default">
                <div className="flex items-center gap-[7px] mb-8 px-2 relative z-20">
                    <button
                        onClick={(e) => { e.stopPropagation(); closeWindow(windowId); }}
                        className="w-3 h-3 rounded-full bg-[#FF5F57] border border-black/5 hover:brightness-90 transition-all flex items-center justify-center cursor-pointer"
                    />
                    <button
                        onClick={(e) => { e.stopPropagation(); minimizeWindow(windowId); }}
                        className="w-3 h-3 rounded-full bg-[#FEBC2E] border border-black/5 hover:brightness-90 transition-all flex items-center justify-center cursor-pointer"
                    />
                    <button
                        onClick={(e) => { e.stopPropagation(); win.isMaximized ? restoreWindow(windowId) : maximizeWindow(windowId); }}
                        className="w-3 h-3 rounded-full bg-[#28C840] border border-black/5 hover:brightness-90 transition-all flex items-center justify-center cursor-pointer"
                    />
                </div>

                <h2 className="text-[11px] font-bold tracking-tight text-black/25 uppercase px-2 mb-4">
                    About me
                </h2>

                <nav className="flex flex-col gap-0.5 relative z-20">
                    {NAV_ITEMS.map((item) => (
                        <button
                            key={item.id}
                            onClick={(e) => { e.stopPropagation(); setActiveSection(item.id); }}
                            className={`relative flex items-center px-4 py-1.5 transition-colors duration-200 group text-[13px] font-semibold rounded-md cursor-pointer ${activeSection === item.id
                                ? "text-black"
                                : "text-black/50 hover:text-black"
                                }`}
                        >
                            {activeSection === item.id && (
                                <motion.div
                                    layoutId="active-about-bar"
                                    className="absolute inset-0 bg-[#FFD600] rounded-md shadow-sm"
                                    transition={{ type: "spring", bounce: 0, duration: 0.3 }}
                                />
                            )}
                            <span className="relative z-10">
                                {item.label}
                            </span>
                        </button>
                    ))}
                </nav>
            </div>

            {/* ── Main Content Area ───────────────────────────────────── */}
            <div className="flex-1 h-full bg-white relative">
                <AnimatePresence mode="wait">
                    <motion.div
                        key={activeSection}
                        initial={{ opacity: 0, y: 5 }}
                        animate={{ opacity: 1, y: 0 }}
                        exit={{ opacity: 0, y: -5 }}
                        transition={{ duration: 0.15 }}
                        className="h-full w-full px-10 py-10 overflow-y-auto hide-scrollbar"
                    >
                        {activeSection === "intro" && <IntroView />}
                        {activeSection === "offer" && <OfferView />}
                        {activeSection === "awards" && <AwardsView />}
                        {activeSection === "clients" && <ClientsView />}
                    </motion.div>
                </AnimatePresence>
            </div>
        </div>
    );
}

// ─── View Components ────────────────────────────────────────────────────────

function IntroView() {
    return (
        <div className="w-full">
            <h1 className="text-[22px] sm:text-[26px] font-bold tracking-tight leading-snug mb-6">
                Hello, my name is <span className="text-[#007AFF]">Dzakwan</span> — I&apos;m a <span className="text-[#FF3B30] bg-[#FFF0F0] px-1.5 py-0.5 rounded-md">creative designer.</span>
            </h1>

            <div className="grid grid-cols-3 gap-3 mb-8">
                {[1, 2, 3].map((i) => (
                    <div key={i} className="aspect-square relative rounded-xl overflow-hidden bg-gray-100 shadow-sm border border-black/5">
                        <div className="absolute inset-0 flex items-center justify-center text-black/10 text-[10px] font-bold uppercase">Portrait {i}</div>
                        <Image
                            src={`https://images.unsplash.com/photo-${i === 1 ? '1534528741775-53994a69daeb' : i === 2 ? '1506794778202-cad84cf45f1d' : '1507003211169-0a1dd7228f2d'}?w=400&h=533&q=80&fit=crop`}
                            alt="About image"
                            fill
                            className="object-cover relative z-10"
                            sizes="(max-width: 1024px) 30vw, 250px"
                        />
                    </div>
                ))}
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                <div className="space-y-6">
                    <div className="space-y-2">
                        <h3 className="text-[13px] font-bold text-black uppercase opacity-60">What I Do</h3>
                        <p className="text-[14px] text-black/80 leading-relaxed font-medium">
                            I craft websites, visual identities, and interactive projects that are both
                            beautiful and user-friendly. My work focuses on translating complex
                            ideas into clear, engaging experiences.
                        </p>
                    </div>

                    <div className="space-y-2">
                        <h3 className="text-[13px] font-bold text-black uppercase opacity-60">My Approach</h3>
                        <p className="text-[14px] text-black/80 leading-relaxed font-medium">
                            I believe design should tell a story and solve problems. I start by
                            understanding the user and project goals, then iterate concepts until I
                            find the perfect balance of form and function.
                        </p>
                    </div>
                </div>

                <div className="space-y-4">
                    <h3 className="text-[13px] font-bold text-black uppercase opacity-60">Connect</h3>
                    <div className="flex flex-col gap-3">
                        <TextSocialLink label="Instagram" href="https://instagram.com" />
                        <TextSocialLink label="X (Twitter)" href="https://twitter.com" />
                        <TextSocialLink label="LinkedIn" href="https://linkedin.com" />
                        <TextSocialLink label="GitHub" href="https://github.com" />
                    </div>
                </div>
            </div>
        </div>
    );
}

function OfferView() {
    return (
        <div className="w-full max-w-[800px]">
            <h2 className="text-[22px] sm:text-[26px] font-bold mb-8 tracking-tight">Services</h2>

            <div className="flex flex-col gap-6 mb-12">
                <OfferItem
                    title="Front-End Web Development"
                    desc="Build responsive, high-performance websites using Next.js, React, and Tailwind CSS."
                />
                <OfferItem
                    title="Mobile App Development"
                    desc="Develop offline-first mobile apps with Flutter and native Android (Kotlin + Jetpack Compose)."
                />
                <OfferItem
                    title="UI/UX Design"
                    desc="Design intuitive user flows, accessible interfaces, and end-to-end product experiences in Figma."
                />
                <OfferItem
                    title="Prototyping & Wireframing"
                    desc="Create low-to-high fidelity wireframes and interactive prototypes for web & mobile."
                />
                <OfferItem
                    title="Design System & Component Library"
                    desc="Build scalable design systems with reusable components to speed up handoff and consistency."
                />
                <OfferItem
                    title="Dashboard & Data Visualization"
                    desc="Deliver KPI dashboards and operational insights (charts, heatmaps, trends) for decision-making."
                />
                <OfferItem
                    title="API Integration & Full-stack Collaboration"
                    desc="Integrate front-end with backend services (e.g., FastAPI, Supabase) cleanly and reliably."
                />
                <OfferItem
                    title="Testing & Production Readiness"
                    desc="Implement auth (JWT/RBAC), automated testing, and production-grade practices for maintainable delivery."
                />
                <OfferItem
                    title="On-device AI Feature Integration"
                    desc="Implement camera + detection workflows (e.g., CameraX + ML Kit) for real-time recognition features."
                />
                <OfferItem
                    title="Leadership & Project Execution"
                    desc="Lead cross-team initiatives, coordinate stakeholders, and execute programs with measurable impact."
                />
            </div>

            <div className="bg-[#F2F2F2] rounded-2xl p-8 mb-4 border border-black/5">
                <p className="font-mono text-[13px] leading-relaxed text-black/70 italic text-center">
                    “I build products that feel smooth to use — combining strong UI/UX with solid engineering. If you need someone who can design and ship, let’s build something impactful.”
                </p>
            </div>
        </div>
    );
}

function AwardsView() {
    return (
        <div className="w-full">
            <h2 className="text-[22px] sm:text-[26px] font-bold mb-8 tracking-tight">Awards & Press</h2>
            <div className="grid grid-cols-1 gap-1">
                < AwardItem year="2024" title="Site of the Year" source="Awwwards" />
                <AwardItem year="2023" title="Design Excellence" source="Behance" />
                <AwardItem year="2023" title="Mobile App of the month" source="FWA" />
                <AwardItem year="2022" title="Young Talent Award" source="Adobe" />
            </div>
        </div>
    );
}

function ClientsView() {
    return (
        <div className="w-full">
            <h2 className="text-[22px] sm:text-[26px] font-bold mb-8 tracking-tight">Selected Clients</h2>
            <div className="grid grid-cols-2 lg:grid-cols-3 gap-6">
                {['Apple', 'Stripe', 'Nike', 'Vercel', 'Linear', 'Airbnb'].map(client => (
                    <div key={client} className="p-8 rounded-2xl bg-[#F5F5F7] border border-black/5 flex items-center justify-center font-bold text-[18px] text-black/30 grayscale hover:grayscale-0 hover:bg-white hover:shadow-md transition-all">
                        {client}
                    </div>
                ))}
            </div>
        </div>
    );
}

// ─── Helpers ───────────────────────────────────────────────────────────

function TextSocialLink({ label, href }: { label: string; href: string }) {
    return (
        <a
            href={href}
            target="_blank"
            rel="noopener noreferrer"
            className="text-[14px] text-[#007AFF] hover:underline w-fit font-semibold"
        >
            {label}
        </a>
    );
}

function OfferItem({ title, desc }: { title: string, desc: string }) {
    return (
        <div className="flex gap-3 group">
            <div className="pt-1 shrink-0">
                <div className="w-4 h-4 rounded-full bg-[#FFB800] flex items-center justify-center text-white shadow-sm">
                    <Check size={10} strokeWidth={4} />
                </div>
            </div>
            <div className="space-y-0.5">
                <p className="text-[12px] leading-snug text-black/80 font-medium">
                    <span className="font-bold">{title}</span> — {desc}
                </p>
            </div>
        </div>
    );
}

function AwardItem({ year, title, source }: { year: string, title: string, source: string }) {
    return (
        <div className="flex items-center justify-between py-4 border-b border-black/5 hover:bg-[#F5F5F7]/50 px-4 -mx-4 rounded-xl transition-all">
            <div className="flex flex-col">
                <span className="text-[15px] font-bold">{title}</span>
                <span className="text-[13px] text-black/40 font-medium">{source}</span>
            </div>
            <span className="text-[13px] font-bold text-black/30 bg-[#F5F5F7] px-3 py-1 rounded-full">{year}</span>
        </div>
    );
}

"use client";

import { motion } from "framer-motion";
import {
    Mail,
    Phone,
    Linkedin,
    Globe,
    MapPin,
    Download,
    Send,
    MessageSquare,
    User,
    AtSign
} from "lucide-react";
import { useState } from "react";
import { toast } from "sonner";

export default function ContactApp() {
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [formData, setFormData] = useState({
        name: "",
        email: "",
        message: ""
    });

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setIsSubmitting(true);

        // Simulate API call
        await new Promise(resolve => setTimeout(resolve, 1500));

        toast.success("Message sent! I'll get back to you soon.");
        setFormData({ name: "", email: "", message: "" });
        setIsSubmitting(false);
    };

    const handleDownloadCV = () => {
        // In a real app, this would be a link to a PDF in the public folder
        toast.info("Downloading Dzakwan's CV...");
        // window.open('/path-to-cv.pdf', '_blank');
    };

    return (
        <div className="h-full bg-background flex flex-col md:flex-row overflow-hidden selection:bg-primary/20">
            {/* ── Left Side: Contact Info ────────────────────────────────── */}
            <div className="flex-1 p-12 flex flex-col justify-center bg-muted/20">
                <motion.div
                    initial={{ opacity: 0, x: -20 }}
                    animate={{ opacity: 1, x: 0 }}
                    transition={{ duration: 0.6 }}
                >
                    <div className="mb-12">
                        <div className="w-12 h-12 rounded-2xl bg-[#D26D4D]/10 flex items-center justify-center text-[#D26D4D] mb-6">
                            <MessageSquare size={24} strokeWidth={2.5} />
                        </div>
                        <h1 className="text-5xl font-black tracking-tighter mb-4">Let&apos;s talk.</h1>
                        <p className="text-lg text-muted-foreground font-medium max-w-[400px]">
                            Have a project in mind or just want to say hi? I&apos;m always open to new opportunities.
                        </p>
                    </div>

                    <div className="space-y-6 mb-12">
                        <ContactItem
                            icon={Mail}
                            label="Email"
                            value="dzakwanfadlullah@gmail.com"
                            href="mailto:dzakwanfadlullah@gmail.com"
                        />
                        <ContactItem
                            icon={Phone}
                            label="Phone"
                            value="(+62) 859 4752 7937"
                            href="tel:+6285947527937"
                        />
                        <ContactItem
                            icon={Linkedin}
                            label="LinkedIn"
                            value="Dzakwan Fadhlullah"
                            href="https://linkedin.com/in/DzakwanFadhlullah"
                        />
                        <ContactItem
                            icon={Globe}
                            label="Portfolio"
                            value="bit.ly/Dzakwan-Portofolio"
                            href="https://bit.ly/Dzakwan-Portofolio"
                        />
                        <ContactItem
                            icon={MapPin}
                            label="Location"
                            value="Bandung, Indonesia"
                        />
                    </div>

                    <button
                        onClick={handleDownloadCV}
                        className="group flex items-center gap-3 bg-[#D26D4D] text-white px-8 py-4 rounded-2xl font-black text-sm tracking-widest uppercase shadow-xl shadow-[#D26D4D]/20 hover:scale-[1.02] active:scale-[0.98] transition-all"
                    >
                        <Download size={18} />
                        Download CV
                        <div className="w-1.5 h-1.5 rounded-full bg-white/40 group-hover:bg-white animate-pulse" />
                    </button>
                </motion.div>
            </div>

            {/* ── Right Side: Contact Form ───────────────────────────────── */}
            <div className="flex-1 p-12 flex flex-col justify-center bg-background border-l border-border/10">
                <motion.div
                    initial={{ opacity: 0, x: 20 }}
                    animate={{ opacity: 1, x: 0 }}
                    transition={{ duration: 0.6, delay: 0.2 }}
                    className="max-w-[480px] w-full mx-auto"
                >
                    <form onSubmit={handleSubmit} className="space-y-6">
                        <div className="space-y-2">
                            <label className="text-[10px] uppercase tracking-[0.2em] font-black text-muted-foreground/60 ml-1">
                                Your Name
                            </label>
                            <div className="relative group">
                                <User className="absolute left-4 top-1/2 -translate-y-1/2 text-muted-foreground/40 group-focus-within:text-[#D26D4D] transition-colors" size={18} />
                                <input
                                    required
                                    type="text"
                                    placeholder="Johnny Appleseed"
                                    value={formData.name}
                                    onChange={e => setFormData({ ...formData, name: e.target.value })}
                                    className="w-full bg-muted/30 border border-border/40 rounded-2xl py-4 pl-12 pr-6 text-sm font-bold focus:outline-none focus:border-[#D26D4D]/40 focus:bg-muted/50 transition-all placeholder:text-muted-foreground/30"
                                />
                            </div>
                        </div>

                        <div className="space-y-2">
                            <label className="text-[10px] uppercase tracking-[0.2em] font-black text-muted-foreground/60 ml-1">
                                Email Address
                            </label>
                            <div className="relative group">
                                <AtSign className="absolute left-4 top-1/2 -translate-y-1/2 text-muted-foreground/40 group-focus-within:text-[#D26D4D] transition-colors" size={18} />
                                <input
                                    required
                                    type="email"
                                    placeholder="john@example.com"
                                    value={formData.email}
                                    onChange={e => setFormData({ ...formData, email: e.target.value })}
                                    className="w-full bg-muted/30 border border-border/40 rounded-2xl py-4 pl-12 pr-6 text-sm font-bold focus:outline-none focus:border-[#D26D4D]/40 focus:bg-muted/50 transition-all placeholder:text-muted-foreground/30"
                                />
                            </div>
                        </div>

                        <div className="space-y-2">
                            <label className="text-[10px] uppercase tracking-[0.2em] font-black text-muted-foreground/60 ml-1">
                                Message
                            </label>
                            <textarea
                                required
                                rows={5}
                                placeholder="Tell me about your project..."
                                value={formData.message}
                                onChange={e => setFormData({ ...formData, message: e.target.value })}
                                className="w-full bg-muted/30 border border-border/40 rounded-2xl p-6 text-sm font-bold focus:outline-none focus:border-[#D26D4D]/40 focus:bg-muted/50 transition-all placeholder:text-muted-foreground/30 resize-none"
                            />
                        </div>

                        <button
                            type="submit"
                            disabled={isSubmitting}
                            className="w-full flex items-center justify-center gap-3 bg-foreground text-background py-5 rounded-2xl font-black text-sm tracking-[0.2em] uppercase hover:bg-foreground/90 active:scale-[0.98] transition-all disabled:opacity-50 disabled:cursor-not-allowed group shadow-lg"
                        >
                            {isSubmitting ? (
                                <div className="flex gap-1.5 items-center">
                                    <div className="w-1.5 h-1.5 rounded-full bg-background animate-bounce [animation-delay:-0.3s]" />
                                    <div className="w-1.5 h-1.5 rounded-full bg-background animate-bounce [animation-delay:-0.15s]" />
                                    <div className="w-1.5 h-1.5 rounded-full bg-background animate-bounce" />
                                </div>
                            ) : (
                                <>
                                    Send Message
                                    <Send size={16} className="group-hover:translate-x-1 group-hover:-translate-y-1 transition-transform" />
                                </>
                            )}
                        </button>
                    </form>
                </motion.div>
            </div>
        </div>
    );
}

function ContactItem({ icon: Icon, label, value, href }: { icon: any; label: string; value: string; href?: string }) {
    const content = (
        <div className="flex items-center gap-4 group cursor-pointer">
            <div className="w-10 h-10 rounded-xl bg-background border border-border/40 flex items-center justify-center text-muted-foreground group-hover:text-[#D26D4D] group-hover:border-[#D26D4D]/20 transition-all shadow-sm">
                <Icon size={18} />
            </div>
            <div>
                <p className="text-[10px] uppercase tracking-widest font-black text-muted-foreground/40 group-hover:text-muted-foreground/60 transition-colors">
                    {label}
                </p>
                <p className="text-sm font-bold text-foreground group-hover:text-[#D26D4D] transition-colors">
                    {value}
                </p>
            </div>
        </div>
    );

    if (href) {
        return (
            <a href={href} target="_blank" rel="noopener noreferrer">
                {content}
            </a>
        );
    }

    return content;
}

"use client";

import { motion, AnimatePresence } from "framer-motion";
import { Keyboard, Spade, Rocket, Circle, Layers } from "lucide-react";
import { useState } from "react";
import { TypingTestDemo } from "./demos/TypingTestDemo";
import { BlackjackDemo } from "./demos/BlackjackDemo";
import { AppleRunnerDemo } from "./demos/AppleRunnerDemo";
import { OrbitFlapDemo } from "./demos/OrbitFlapDemo";
import { TheStackDemo } from "./demos/TheStackDemo";
import { VirusProtocolDemo } from "./demos/VirusProtocolDemo";
import { LabSidebar, LabSectionId } from "./LabSidebar";

export default function LabApp() {
    const [activeSection, setActiveSection] = useState<LabSectionId>("typing");

    return (
        <div className="h-full flex flex-row overflow-hidden font-sans select-none">
            {/* ── Sidebar ────────────────────────────────────────── */}
            <LabSidebar activeSection={activeSection} onSectionChange={setActiveSection} />

            {/* ── Main Content Area ───────────────────────────────────── */}
            <div className="flex-1 h-full bg-card/50 backdrop-blur-md relative overflow-hidden flex flex-col">
                <AnimatePresence mode="wait">
                    <motion.div
                        key={activeSection}
                        initial={{ opacity: 0, y: 10 }}
                        animate={{ opacity: 1, y: 0 }}
                        exit={{ opacity: 0, y: -10 }}
                        transition={{ duration: 0.2, ease: "easeOut" }}
                        className="flex-1 flex flex-col overflow-y-auto px-6 py-8 md:px-10 md:py-12 hide-scrollbar"
                    >
                        {/* ── Header ────────────────────────────────────────── */}
                        <div className="mb-12">
                            <h1 className="text-[26px] font-bold tracking-tight mb-2 text-foreground">
                                {activeSection === "typing" ? "Keyboard Test" : activeSection === "blackjack" ? "Blackjack" : activeSection === "applerunner" ? "Apple Runner" : activeSection === "orbitflap" ? "Orbit Flap" : activeSection === "thestack" ? "The Stack" : activeSection === "virusprotocol" ? "Virus Protocol" : "Game Center"}
                            </h1>
                            <p className="max-w-[600px] text-[15px] text-foreground/50 leading-relaxed font-medium">
                                Test your skills with fun
                                <span className="text-[#007AFF]"> mini games</span>.
                            </p>
                        </div>

                        {/* ── Game Grid / Canvas ─────────────────────────────────────────── */}
                        {(activeSection === "typing" || activeSection === "blackjack") ? (
                            <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-8 pb-20">
                                {activeSection === "typing" && (
                                    <div className="col-span-1 md:col-span-2 xl:col-span-3">
                                        <DemoContainer title="Keyboard Test" icon={Keyboard} className="!aspect-auto min-h-[500px] h-fit sm:min-h-[550px]">
                                            <TypingTestDemo />
                                        </DemoContainer>
                                    </div>
                                )}

                                {activeSection === "blackjack" && (
                                    <div className="col-span-1 md:col-span-2 xl:col-span-3">
                                        <DemoContainer title="Blackjack" icon={Spade} className="!aspect-auto min-h-[550px] h-fit sm:min-h-[600px]">
                                            <BlackjackDemo />
                                        </DemoContainer>
                                    </div>
                                )}
                            </div>
                        ) : (
                            <div className="flex-1 w-full min-h-[500px] md:min-h-[600px] rounded-[2rem] overflow-hidden border border-black/[0.08] shadow-[0_20px_40px_rgba(0,0,0,0.12)] relative bg-white/50">
                                {activeSection === "applerunner" && <AppleRunnerDemo />}
                                {activeSection === "orbitflap" && <OrbitFlapDemo />}
                                {activeSection === "thestack" && <TheStackDemo />}
                                {activeSection === "virusprotocol" && <VirusProtocolDemo />}
                            </div>
                        )}
                    </motion.div>
                </AnimatePresence>
            </div>
        </div>
    );
}

function DemoContainer({ title, icon: Icon, children, className }: { title: string; icon: any; children: React.ReactNode, className?: string }) {
    return (
        <motion.div
