"use client";

import { motion, AnimatePresence } from "framer-motion";
import Image from "next/image";
import {
    Play,
    Pause,
    SkipBack,
    SkipForward,
    Volume2,
    Repeat,
    Shuffle,
    ListMusic,
    Mic2,
    Airplay,
    MoreHorizontal,
    Heart,
    Plus,
    Clock,
    Music2
} from "lucide-react";
import { useState, useRef, useEffect } from "react";
import { SONGS, Song } from "./musicData";
import LyricsView from "./LyricsView";
import { parseLRC } from "@/lib/lrcParser";

export default function MusicApp() {
    const [currentSongIndex, setCurrentSongIndex] = useState(0);
    const [isPlaying, setIsPlaying] = useState(false);
    const [currentTime, setCurrentTime] = useState(0);
    const [duration, setDuration] = useState(0);
    const [showLyrics, setShowLyrics] = useState(true);
    const [volume, setVolume] = useState(0.8);
    const [isShuffle, setIsShuffle] = useState(false);
    const [isRepeat, setIsRepeat] = useState<"none" | "all" | "one">("none");
    const [lyricsWidth, setLyricsWidth] = useState(450);
    const [isResizing, setIsResizing] = useState(false);

    const audioRef = useRef<HTMLAudioElement>(null);
    const appRef = useRef<HTMLDivElement>(null);
    const currentSong = (SONGS[currentSongIndex] || SONGS[0]) as Song;

    // Use parsed LRC if available, otherwise fallback to static lyrics array
    const displayLyrics = currentSong.lrcContents
        ? parseLRC(currentSong.lrcContents)
        : currentSong.lyrics;

    useEffect(() => {
        if (audioRef.current) {
            if (isPlaying) {
                audioRef.current.play().catch(() => setIsPlaying(false));
            } else {
                audioRef.current.pause();
            }
        }
    }, [isPlaying, currentSongIndex]);

    useEffect(() => {
        if (audioRef.current) {
            audioRef.current.volume = volume;
        }
    }, [volume]);

    useEffect(() => {
        const handleMouseMove = (e: MouseEvent) => {
            if (!isResizing || !appRef.current) return;
            const rect = appRef.current.getBoundingClientRect();
            const newWidth = rect.right - e.clientX;
            // Limit width between 300px and 800px
            if (newWidth > 300 && newWidth < 800) {
                setLyricsWidth(newWidth);
            }
        };

        const handleMouseUp = () => {
            setIsResizing(false);
        };

        if (isResizing) {
            window.addEventListener("mousemove", handleMouseMove);
            window.addEventListener("mouseup", handleMouseUp);
        }

        return () => {
            window.removeEventListener("mousemove", handleMouseMove);
            window.removeEventListener("mouseup", handleMouseUp);
        };
    }, [isResizing]);

    const handleSeek = (e: React.MouseEvent<HTMLDivElement>) => {
        if (audioRef.current && duration) {
            const rect = e.currentTarget.getBoundingClientRect();
            const percent = (e.clientX - rect.left) / rect.width;
            audioRef.current.currentTime = percent * duration;
        }
    };

    const handleSeekTo = (time: number) => {
        if (audioRef.current) {
            audioRef.current.currentTime = time;
            if (!isPlaying) setIsPlaying(true);
        }
    };

    const handleVolumeChange = (e: React.MouseEvent<HTMLDivElement>) => {
        const rect = e.currentTarget.getBoundingClientRect();
        const newVolume = Math.max(0, Math.min(1, (e.clientX - rect.left) / rect.width));
        setVolume(newVolume);
    };

    const handleTimeUpdate = () => {
        if (audioRef.current) {
            setCurrentTime(audioRef.current.currentTime);
        }
    };

    const handleLoadedMetadata = () => {
        if (audioRef.current) {
            setDuration(audioRef.current.duration);
        }
    };

    const handleSongEnd = () => {
        if (isRepeat === "one") {
            if (audioRef.current) {
                audioRef.current.currentTime = 0;
                audioRef.current.play();
            }
        } else if (isShuffle) {
            let nextIndex;
            do {
                nextIndex = Math.floor(Math.random() * SONGS.length);
            } while (nextIndex === currentSongIndex && SONGS.length > 1);
            setCurrentSongIndex(nextIndex);
        } else if (isRepeat === "all") {
            handleNext();
        } else {
            // Repeat none: only play next if it's not the last song
            if (currentSongIndex < SONGS.length - 1) {
                handleNext();
            } else {
                setIsPlaying(false);
            }
        }
    };

    const handleNext = () => {
        setCurrentSongIndex((prev) => (prev + 1) % SONGS.length);
    };

    const handlePrev = () => {
        setCurrentSongIndex((prev) => (prev - 1 + SONGS.length) % SONGS.length);
    };

    const formatTime = (time: number) => {
        const minutes = Math.floor(time / 60);
        const seconds = Math.floor(time % 60);
        return `${minutes}:${seconds.toString().padStart(2, "0")}`;
    };

    return (
        <div
            ref={appRef}
            className="h-full flex flex-col bg-[#F9F9F9] text-[#1C1C1E] overflow-hidden font-sans selection:bg-[#FA233B]/20 rounded-2xl"
        >
            <div className="flex-1 flex overflow-hidden">
                {/* ── Sidebar ────────────────────────────────────────── */}
                <aside className="w-64 bg-[#EBEBEB]/50 border-r border-[#D1D1D1] flex flex-col p-5 h-full">
                    <div className="flex items-center gap-2 mb-8 px-2">
                        <Image src="/musicapple.png" alt="Music" width={24} height={24} className="object-contain" />
                        <span className="font-bold text-lg tracking-tight">Music</span>
                    </div>

                    <div className="space-y-6">
                        <section>
                            <h3 className="text-[11px] font-bold text-black/40 uppercase tracking-widest px-3 mb-2">Apple Music</h3>
                            <nav className="space-y-0.5">
                                {["Listen Now", "Browse", "Radio"].map((item) => (
                                    <button key={item} className="w-full flex items-center gap-2 px-3 py-1.5 rounded-md text-sm font-medium hover:bg-black/5 transition-colors text-left">
                                        {item}
                                    </button>
                                ))}
                            </nav>
                        </section>

                        <section>
                            <h3 className="text-[11px] font-bold text-black/40 uppercase tracking-widest px-3 mb-2">Library</h3>
                            <nav className="space-y-0.5">
                                {["Recently Added", "Artists", "Albums", "Songs"].map((item) => (
                                    <button
                                        key={item}
                                        className={`w-full flex items-center gap-2 px-3 py-1.5 rounded-md text-sm font-medium transition-colors text-left ${item === "Songs" ? "bg-[#FA233B] text-white shadow-sm" : "hover:bg-black/5"}`}
                                    >
                                        {item}
                                    </button>
                                ))}
                            </nav>
                        </section>
                    </div>
                </aside>

                {/* ── Main Content ─────────────────────────────────────── */}
                <main className="flex-1 flex flex-col overflow-hidden bg-white">
                    <div className="flex-1 overflow-y-auto custom-scrollbar p-12">
                        <div className="max-w-[800px] mx-auto">
                            {/* Hero Header */}
                            <div className="flex gap-10 mb-12">
                                <motion.div
                                    layoutId={`cover-${currentSong.id}`}
                                    className="relative w-64 h-64 rounded-xl shadow-[0_20px_50px_rgba(0,0,0,0.15)] overflow-hidden flex-shrink-0"
                                >
                                    <Image src={currentSong.cover} alt={currentSong.title} fill className="object-cover" unoptimized />
                                </motion.div>
                                <div className="flex flex-col justify-end py-2">
                                    <div className="flex items-center gap-2 mb-2">
                                        <Image src="/musicapple.png" alt="Music" width={20} height={20} className="object-contain" />
                                        <div className="text-[10px] font-bold text-[#FA233B] uppercase tracking-widest">Apple Music</div>
                                    </div>
                                    <h1 className="text-4xl font-bold tracking-tight mb-1">{currentSong.title}</h1>
                                    <p className="text-2xl text-[#FA233B] font-medium mb-6">{currentSong.artist}</p>
                                    <p className="text-sm text-black/40 font-medium mb-8">
                                        POP · 2026 · <span className="uppercase">Dolby Atmos</span> · LOSSLESS
                                    </p>
                                    <div className="flex gap-3">
                                        <button
                                            onClick={() => setIsPlaying(!isPlaying)}
                                            className="flex items-center justify-center gap-2 bg-[#F2F2F7] hover:bg-[#E5E5EA] text-[#1C1C1E] px-8 py-2.5 rounded-lg font-bold transition-all min-w-[140px]"
                                        >
                                            {isPlaying ? <Pause size={18} fill="currentColor" /> : <Play size={18} fill="currentColor" />}
                                            {isPlaying ? "Pause" : "Play"}
                                        </button>
                                        <button
                                            onClick={() => setIsShuffle(!isShuffle)}
                                            className={`flex items-center justify-center gap-2 px-8 py-2.5 rounded-lg font-bold transition-all min-w-[140px] ${isShuffle ? "bg-[#FA233B] text-white shadow-md" : "bg-[#F2F2F7] hover:bg-[#E5E5EA] text-[#1C1C1E]"}`}
                                        >
                                            <Shuffle size={18} />
                                            Shuffle
                                        </button>
                                    </div>
                                </div>
                            </div>

                            {/* Song List */}
                            <div className="mt-8">
                                <table className="w-full text-left border-collapse">
                                    <thead>
                                        <tr className="border-b border-black/5 text-[11px] font-bold text-black/30 uppercase tracking-widest">
                                            <th className="py-3 pr-4 font-bold">#</th>
                                            <th className="py-3">Song</th>
                                            <th className="py-3 text-right"><Clock size={14} className="ml-auto" /></th>
                                            <th className="py-3 w-10"></th>
                                        </tr>
                                    </thead>
                                    <tbody className="text-sm">
                                        {SONGS.map((song, index) => {
                                            const isSelected = index === currentSongIndex;
                                            return (
                                                <tr
                                                    key={song.id}
                                                    onClick={() => {
                                                        setCurrentSongIndex(index);
                                                        setIsPlaying(true);
                                                    }}
                                                    className={`group border-b border-black/5 hover:bg-black/[0.02] cursor-pointer transition-colors ${isSelected ? "bg-black/[0.04]" : ""}`}
                                                >
                                                    <td className="py-3 pr-4 text-black/40 font-medium w-8">
                                                        {isSelected && isPlaying ? (
                                                            <div className="flex items-end gap-[2px] h-3 mb-0.5">
                                                                <motion.div animate={{ height: [4, 12, 6, 10, 4] }} transition={{ repeat: Infinity, duration: 0.8 }} className="w-1 bg-[#FA233B] rounded-full" />
                                                                <motion.div animate={{ height: [8, 4, 10, 6, 8] }} transition={{ repeat: Infinity, duration: 0.6 }} className="w-1 bg-[#FA233B] rounded-full" />
                                                                <motion.div animate={{ height: [12, 4, 8, 4, 12] }} transition={{ repeat: Infinity, duration: 0.7 }} className="w-1 bg-[#FA233B] rounded-full" />
                                                            </div>
                                                        ) : index + 1}
                                                    </td>
                                                    <td className={`py-3 font-medium ${isSelected ? "text-[#FA233B]" : "text-black"}`}>
                                                        {song.title}
                                                    </td>
                                                    <td className="py-3 text-right text-black/40 tabular-nums">
                                                        {song.duration}
                                                    </td>
                                                    <td className="py-3 text-right">
                                                        <MoreHorizontal size={14} className="opacity-0 group-hover:opacity-100 text-black/40 transition-opacity ml-auto" />
                                                    </td>
                                                </tr>
                                            );
                                        })}
                                    </tbody>
                                </table>
                            </div>
                        </div>
                    </div>
                </main>

                {/* ── Lyrics View ───────────────────────────────────────── */}
                <AnimatePresence>
                    {showLyrics && (
                        <>
                            {/* Resizer Divider */}
                            <div
                                className="w-[1px] bg-[#D1D1D1] hover:bg-[#FA233B] hover:w-1 cursor-col-resize transition-all z-20 group relative h-full hidden xl:block"
                                onMouseDown={() => setIsResizing(true)}
                            >
                                <div className="absolute inset-y-0 -left-1 -right-1 cursor-col-resize" />
                            </div>

                            <motion.aside
                                initial={{ width: 0, opacity: 0 }}
                                animate={{ width: lyricsWidth, opacity: 1 }}
                                exit={{ width: 0, opacity: 0 }}
                                className="bg-white overflow-hidden hidden xl:block"
                                style={{ width: lyricsWidth }}
                            >
                                <LyricsView
                                    lyrics={displayLyrics}
                                    currentTime={currentTime}
                                    onSeek={handleSeekTo}
                                />
                            </motion.aside>
                        </>
                    )}
                </AnimatePresence>
            </div>

            {/* ── Player Bar ─────────────────────────────────────────── */}
            <footer className="h-20 bg-white/80 backdrop-blur-xl border-t border-[#D1D1D1] px-6 flex items-center justify-between z-10 rounded-b-2xl">
                {/* Track Info */}
                <div className="flex items-center gap-3 w-1/3">
                    <div className="relative w-12 h-12 rounded-lg overflow-hidden shadow-lg border border-black/5">
                        <Image src={currentSong.cover} alt="" fill className="object-cover" unoptimized />
                    </div>
                    <div className="overflow-hidden">
                        <h4 className="text-sm font-bold truncate">{currentSong.title}</h4>
                        <p className="text-[12px] text-black/40 font-medium truncate">{currentSong.artist}</p>
                    </div>
                    <Heart size={16} className="text-black/20 hover:text-[#FA233B] cursor-pointer ml-2" />
                </div>

                {/* Controls */}
                <div className="flex flex-col items-center gap-1.5 w-1/3">
                    <div className="flex items-center gap-6">
                        <button
                            onClick={() => setIsShuffle(!isShuffle)}
                            className={`transition-colors ${isShuffle ? "text-[#FA233B]" : "text-black/30 hover:text-black"}`}
                        >
                            <Shuffle size={18} />
                        </button>
                        <button onClick={handlePrev} className="text-black hover:text-[#FA233B] transition-colors"><SkipBack size={20} fill="currentColor" /></button>
                        <button
                            onClick={() => setIsPlaying(!isPlaying)}
                            className="w-10 h-10 flex items-center justify-center bg-black rounded-full text-white hover:scale-105 active:scale-95 transition-all"
                        >
                            {isPlaying ? <Pause size={20} fill="currentColor" /> : <Play size={20} fill="currentColor" className="ml-0.5" />}
                        </button>
                        <button onClick={handleNext} className="text-black hover:text-[#FA233B] transition-colors"><SkipForward size={20} fill="currentColor" /></button>
                        <button
                            onClick={() => setIsRepeat(isRepeat === "none" ? "all" : isRepeat === "all" ? "one" : "none")}
                            className={`transition-colors relative ${isRepeat !== "none" ? "text-[#FA233B]" : "text-black/30 hover:text-black"}`}
                        >
                            <Repeat size={18} />
                            {isRepeat === "one" && <span className="absolute -top-1 -right-1 text-[8px] font-bold">1</span>}
                        </button>
                    </div>

                    {/* Progress */}
                    <div className="w-full max-w-md flex items-center gap-3">
                        <span className="text-[10px] tabular-nums font-bold text-black/30 w-8 text-right">{formatTime(currentTime)}</span>
                        <div
                            className="flex-1 h-1.5 bg-black/5 rounded-full relative group cursor-pointer"
                            onClick={handleSeek}
                        >
                            <motion.div
                                className="h-full bg-black/60 rounded-full relative"
                                style={{ width: `${(currentTime / duration) * 100}%` || "0%" }}
                            >
                                <div className="absolute right-0 top-1/2 -translate-y-1/2 w-3 h-3 bg-white border-2 border-black/20 rounded-full opacity-0 group-hover:opacity-100 shadow-sm transition-opacity" />
                            </motion.div>
                        </div>
                        <span className="text-[10px] tabular-nums font-bold text-black/30 w-8">-{formatTime(duration - currentTime)}</span>
                    </div>
                </div>

                {/* Extra Controls */}
                <div className="flex items-center justify-end gap-5 w-1/3">
                    <button
                        onClick={() => setShowLyrics(!showLyrics)}
                        className={`transition-colors ${showLyrics ? "text-[#FA233B]" : "text-black/30 hover:text-black"}`}
                    >
                        <Mic2 size={18} />
                    </button>
                    <div className="flex items-center gap-2 group">
                        <Volume2 size={18} className="text-black/30" />
                        <div
                            className="w-24 h-1.5 bg-black/5 rounded-full overflow-hidden cursor-pointer"
                            onClick={handleVolumeChange}
                        >
                            <div className="h-full bg-black/30" style={{ width: `${volume * 100}%` }} />
                        </div>
                    </div>
                    <button className="text-black/30 hover:text-black transition-colors"><Airplay size={18} /></button>
                    <button className="text-black/30 hover:text-black transition-colors"><ListMusic size={18} /></button>
                </div>
            </footer>

            <audio
                ref={audioRef}
                src={currentSong.audioUrl}
                onTimeUpdate={handleTimeUpdate}
                onLoadedMetadata={handleLoadedMetadata}
                onEnded={handleSongEnd}
            />

            <style jsx>{`
                .custom-scrollbar::-webkit-scrollbar {
                    width: 6px;
                }
                .custom-scrollbar::-webkit-scrollbar-track {
                    background: transparent;
                }
                .custom-scrollbar::-webkit-scrollbar-thumb {
                    background: rgba(0, 0, 0, 0.05);
                    border-radius: 10px;
                }
                .custom-scrollbar::-webkit-scrollbar-thumb:hover {
                    background: rgba(0, 0, 0, 0.1);
                }
            `}</style>
        </div>
    );
}

"use client";

import { useEffect, useState } from "react";
import Image from "next/image";
import { ChevronLeft, ChevronRight, Info, ExternalLink, Github } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import { useWindowActions } from "../../os/WindowContext";
import { useWindowStore } from "@/stores/useWindowStore";
import { projects, type Project } from "./data";

export default function ProjectDetail() {
    const { metadata, setHeaderActions } = useWindowActions();
    const openWindow = useWindowStore((s) => s.openWindow);

    const [currentIndex, setCurrentIndex] = useState(() => {
        const id = metadata?.projectId;
        return projects.findIndex((p) => p.id === id) || 0;
    });

    const project = projects[currentIndex] || projects[0];

    // Navigation logic
    const handlePrev = () => {
        setCurrentIndex((prev) => (prev > 0 ? prev - 1 : projects.length - 1));
    };

    const handleNext = () => {
        setCurrentIndex((prev) => (prev < projects.length - 1 ? prev + 1 : 0));
    };

    // Register navigation arrows in title bar
    useEffect(() => {
        setHeaderActions(
            <div className="flex items-center gap-1 bg-muted/20 p-0.5 rounded-md border border-border/10">
                <button
                    onClick={handlePrev}
                    className="p-1 rounded hover:bg-black/5 text-black/40 hover:text-black transition-colors"
                >
                    <ChevronLeft size={16} strokeWidth={2.5} />
                </button>
                <div className="w-[1px] h-3 bg-black/10 mx-0.5" />
                <button
                    onClick={handleNext}
                    className="p-1 rounded hover:bg-black/5 text-black/40 hover:text-black transition-colors"
                >
                    <ChevronRight size={16} strokeWidth={2.5} />
                </button>
            </div>
        );
        return () => setHeaderActions(null);
    }, [currentIndex, setHeaderActions]);

    if (!project) return null;

    return (
        <div className="relative flex flex-col h-full bg-white overflow-hidden font-sans select-none selection:bg-[#FFD600]/30">
            {/* ── Content Area ────────────────────────────────────────────── */}
            <div className="flex-1 overflow-y-auto pt-16 pb-24 px-12 sm:px-20 hide-scrollbar">
                <div className="max-w-[1000px] mx-auto">
                    <AnimatePresence mode="wait">
                        <motion.div
                            key={project.id}
                            initial={{ opacity: 0, y: 10 }}
                            animate={{ opacity: 1, y: 0 }}
                            exit={{ opacity: 0, y: -10 }}
                            transition={{ duration: 0.3, ease: "easeOut" }}
                        >
                            {/* Metadata Label */}
                            <div className="flex items-center gap-2 mb-4">
                                <span className="text-[11px] font-black uppercase tracking-[0.2em] text-[#007AFF]">Project Detail</span>
                                <div className="h-[1px] w-8 bg-[#007AFF]/20" />
                            </div>

                            {/* Project Name (Hero Typography) */}
                            <h1 className="text-5xl sm:text-6xl font-black tracking-tighter leading-[0.9] mb-10 text-black">
                                {project.name}
                            </h1>

                            {/* Hero Image Section */}
                            <div className="relative aspect-[16/9] w-full rounded-2xl overflow-hidden mb-12 border border-black/5 shadow-os-medium group">
                                <Image
                                    src={project.thumbnail}
                                    alt={project.name}
                                    fill
                                    className="object-cover group-hover:scale-[1.02] transition-transform duration-700"
                                    priority
                                />
                            </div>

                            {/* Integrated Info & Description Grid */}
                            <div className="grid grid-cols-1 lg:grid-cols-12 gap-16">
                                {/* Left Side: Details */}
                                <div className="lg:col-span-8 space-y-12">
                                    <section>
                                        <h3 className="text-[13px] font-bold text-black uppercase opacity-25 mb-4 tracking-wider">Overview</h3>
                                        <p className="text-[17px] text-black/80 leading-relaxed font-semibold">
                                            {project.description}
                                        </p>
                                    </section>

                                    <section>
                                        <h3 className="text-[13px] font-bold text-black uppercase opacity-25 mb-4 tracking-wider">The Approach</h3>
                                        <div className="space-y-6 text-[15px] font-medium text-black/60 leading-relaxed">
                                            <p>
                                                As the {project.role}, I focused on creating a seamless user experience while maintaining technical excellence.
                                                The core challenge was ensuring the system remained performant and accessible across all platforms.
                                            </p>
                                            <p>
                                                I implemented a modular architecture that allowed for easy scaling and maintenance.
                                                By using state-of-the-art technologies and design patterns, we achieved a significant
                                                improvement in user engagement and overall system stability.
                                            </p>
                                        </div>
                                    </section>
                                </div>

                                {/* Right Side: Sidebar Info (Inline) */}
                                <div className="lg:col-span-4 space-y-10">
                                    <div className="grid grid-cols-2 lg:grid-cols-1 gap-10">
                                        <DetailItem label="Year" value={project.year} />
                                        <DetailItem label="Role" value={project.role} />
                                        <DetailItem label="Brand" value={project.brand} />

                                        <section className="space-y-4">
                                            <h3 className="text-[11px] font-bold text-black uppercase opacity-25 tracking-[0.1em]">Stack</h3>
                                            <div className="flex flex-wrap gap-1.5">
                                                {project.tags.map(tag => (
                                                    <span key={tag} className="px-2.5 py-1 bg-black/[0.03] rounded-md text-[11px] font-bold text-black/60 border border-black/5">
                                                        {tag}
                                                    </span>
                                                ))}
                                            </div>
                                        </section>
                                    </div>

                                    {/* Actions */}
                                    <div className="pt-6 flex flex-col gap-3">
                                        <button className="w-full bg-black text-white text-[13px] font-bold h-11 rounded-xl hover:bg-black/90 transition-all flex items-center justify-center gap-2 shadow-lg shadow-black/10">
                                            <ExternalLink size={16} />
                                            Live Project
                                        </button>
                                        <button className="w-full bg-white text-black h-11 rounded-xl hover:bg-black/5 transition-colors flex items-center justify-center gap-2 border border-black/5 font-bold text-[13px]">
                                            <Github size={16} />
                                            Source Code
                                        </button>
                                    </div>
                                </div>
                            </div>
                        </motion.div>
                    </AnimatePresence>
                </div>
            </div>
        </div>
    );
}

function DetailItem({ label, value }: { label: string; value: string }) {
    return (
        <div className="space-y-1">
            <h4 className="text-[11px] font-bold text-black uppercase opacity-25 tracking-[0.1em]">{label}</h4>
            <p className="font-bold text-[15px] text-black/90">{value}</p>
        </div>
    );
}

"use client";

import { useCallback, useMemo, useRef, useEffect } from "react";

import { AnimatePresence } from "framer-motion";
import { useDesktopStore } from "@/stores/useDesktopStore";
import { useWindowStore } from "@/stores/useWindowStore";
import { Z_LAYERS } from "@/hooks/useZIndex";
import { DesktopIcon } from "./DesktopIcon";
import { MenuBar } from "./MenuBar";
import { Dock } from "./Dock";
import { InfoCard } from "./InfoCard";
import { Window } from "./Window";
import { SnapOverlay } from "./SnapOverlay";
import { Spotlight } from "./Spotlight";

// ─── Desktop Component ──────────────────────────────────────────────────────

export const Desktop = () => {
    const containerRef = useRef<HTMLDivElement>(null);
    const icons = useDesktopStore((s) => s.icons);
    const deselectAll = useDesktopStore((s) => s.deselectAll);
    const wallpaper = useDesktopStore((s) => s.wallpaper);
    const windows = useWindowStore((s) => s.windows);
    const setDesktopSize = useWindowStore((s) => s.setDesktopSize);

    // Sync container size with store
    useEffect(() => {
        if (!containerRef.current) return;

        const observer = new ResizeObserver((entries) => {
            for (const entry of entries) {
                const { width, height } = entry.contentRect;
                setDesktopSize({ w: width, h: height });
            }
        });

        observer.observe(containerRef.current);
        return () => observer.disconnect();
    }, [setDesktopSize]);

    const allWindows = useMemo(
        () => Object.values(windows),
        [windows]
    );

    const handleDesktopClick = useCallback(
        (e: React.MouseEvent) => {
            if (e.target === e.currentTarget) {
                deselectAll();
            }
        },
        [deselectAll]
    );

    const handleContextMenu = useCallback(
        (e: React.MouseEvent) => {
            e.preventDefault();
        },
        []
    );

    return (
        <div
            ref={containerRef}
            className="relative h-full w-full overflow-hidden select-none vibrant-wallpaper"
            style={{ zIndex: Z_LAYERS.DESKTOP }}
        >
            {/* ── Desktop Texture Overlay ─────────────────────────────────────── */}
            <div className="absolute inset-0 bg-white/5 backdrop-blur-[1px] grain pointer-events-none" />

            {/* ── Desktop Icon Area ─────────────────────────────────────────── */}
            <div
                className="absolute inset-0"
                style={{
                    zIndex: Z_LAYERS.DESKTOP_ICONS,
                }}
                onClick={handleDesktopClick}
                onContextMenu={handleContextMenu}
            >
                {icons.map((icon) => (
                    <DesktopIcon key={icon.appId} icon={icon} />
                ))}
            </div>

            {/* ── Windows Layer ─────────────────────────────────────────────── */}
            <div
                className="absolute inset-0 pointer-events-none"
                style={{ zIndex: Z_LAYERS.WINDOWS_BASE }}
            >
                <AnimatePresence>
                    {allWindows.map((win) => (
                        <div
                            key={win.id}
                            style={{
                                display: win.isMinimized ? "none" : "block",
                                pointerEvents: "none",
                            }}
                        >
                            <Window windowId={win.id} />
                        </div>
                    ))}
                </AnimatePresence>
            </div>

            {/* ── Shell Components ─────────────────────────────────────────── */}
            <MenuBar />
            <InfoCard />
            <SnapOverlay />
            <Dock />
            <Spotlight />
        </div>
    );
};

"use client";

import { useCallback, useRef } from "react";
import { motion } from "framer-motion";

import { useDesktopStore, type DesktopIcon as DesktopIconType } from "@/stores/useDesktopStore";
import { useWindowStore } from "@/stores/useWindowStore";
import { useAppRegistry } from "@/stores/useAppRegistry";
import { AppleIcon } from "./AppleIcon";
import { projects } from "../apps/projects/data";
import type { AppId } from "@/types/app";

// ─── Props ───────────────────────────────────────────────────────────────────

interface DesktopIconProps {
    icon: DesktopIconType;
}

// ─── Component ───────────────────────────────────────────────────────────────

export const DesktopIcon = ({ icon }: DesktopIconProps) => {
    const { selectedIcons, selectIcon, deselectAll } = useDesktopStore();
    const { openWindow } = useWindowStore();
    const { getApp } = useAppRegistry();
    const lastClickTime = useRef(0);

    const app = getApp(icon.appId);
    const isSelected = selectedIcons.includes(icon.appId);

    // Find matching project thumbnail for "photo" style
    const project = projects.find(p => p.name === icon.label);
    const thumbnail = project?.thumbnail;

    const handleClick = useCallback(
        (e: React.MouseEvent) => {
            e.stopPropagation();

            const now = Date.now();
            const timeSinceLastClick = now - lastClickTime.current;
            lastClickTime.current = now;

            // Double-click detection (< 400ms)
            if (timeSinceLastClick < 400) {
                if (app) {
                    openWindow(
                        icon.appId,
                        app.name,
                        app.defaultWindowConfig.defaultWidth,
                        app.defaultWindowConfig.defaultHeight,
                        project ? { projectId: project.id } : undefined
                    );
                }
                deselectAll();
                return;
            }

            selectIcon(icon.appId);
        },
        [app, icon.appId, openWindow, deselectAll, selectIcon, project]
    );

    if (!app) return null;

    return (
        <motion.div
            className="absolute flex flex-col items-center gap-2 cursor-pointer group"
            style={{
                right: icon.position.x + 48, // Now relative to the right edge
                top: icon.position.y,
                width: 100,
            }}
            onClick={handleClick}
            whileHover={{ scale: 1.02 }}
            whileTap={{ scale: 0.98 }}
        >
            {/* Project Card Container */}
            <div
                className={`
          relative flex items-center justify-center
          w-[84px] h-[84px] rounded-lg
          transition-all duration-300
          ${isSelected
                        ? "shadow-[0_0_0_2px_rgba(255,255,255,0.8)] border-2 border-black/20"
                        : "group-hover:translate-y-[-2px]"
                    }
        `}
            >
                {/* Premium Project Card (Photo Frame style) */}
                <div className="w-[80px] h-[80px]">
                    <AppleIcon
                        {...app.iconConfig}
                        image={thumbnail}
                        style="photo"
                        size={40}
                    />
                </div>
            </div>

            {/* Label */}
            <span
                className={`
          text-[13px] text-center font-bold tracking-tight
          max-w-[90px] truncate select-none
          transition-colors duration-200
          ${isSelected
                        ? "text-white bg-white/30 backdrop-blur-md px-2 py-0.5 rounded-md"
                        : "text-white drop-shadow-[0_2px_2px_rgba(0,0,0,0.8)] group-hover:text-white/90"
                    }
        `}
            >
                {icon.label}
            </span>
        </motion.div>
    );
};

"use client";

import { useCallback, useMemo, useRef } from "react";
import {
    motion,
    useMotionValue,
    useSpring,
    useTransform,
    type MotionValue,
} from "framer-motion";

import { useWindowStore } from "@/stores/useWindowStore";
import { useAppRegistry } from "@/stores/useAppRegistry";
import { Z_LAYERS } from "@/hooks/useZIndex";
import { AppleIcon } from "./AppleIcon";
import type { AppId } from "@/types/app";

// ─── Constants ───────────────────────────────────────────────────────────────

const ICON_SIZE = 48;
const MAGNIFIED_SIZE = 68;
const DOCK_GAP = 6;
const MAGNIFICATION_DISTANCE = 140;

// ─── Dock Icon ───────────────────────────────────────────────────────────────

interface DockIconProps {
    appId: AppId;
    mouseX: MotionValue<number>;
    index: number;
}

const DockIcon = ({ appId, mouseX, index }: DockIconProps) => {
    const ref = useRef<HTMLDivElement>(null);
    const getApp = useAppRegistry((s) => s.getApp);
    const openWindow = useWindowStore((s) => s.openWindow);
    const windows = useWindowStore((s) => s.windows);

    const app = getApp(appId);

    // Check if this app has open windows
    const windowState = useMemo(() => {
        const appWindows = Object.values(windows).filter((w) => w.appId === appId);
        const hasOpenWindow = appWindows.length > 0;
        const hasMinimized = appWindows.some((w) => w.isMinimized);
        const hasActive = appWindows.some((w) => w.isFocused);
        return { hasOpenWindow, hasMinimized, hasActive };
    }, [windows, appId]);

    // Magnification based on mouse distance
    const distance = useTransform(mouseX, (val: number) => {
        const el = ref.current;
        if (!el) return MAGNIFICATION_DISTANCE + 1;
        const rect = el.getBoundingClientRect();
        const center = rect.left + rect.width / 2;
        return Math.abs(val - center);
    });

    const size = useSpring(
        useTransform(distance, [0, MAGNIFICATION_DISTANCE], [MAGNIFIED_SIZE, ICON_SIZE]),
        { stiffness: 400, damping: 25, mass: 0.5 }
    );

    const handleClick = useCallback(() => {
        if (!app) return;

        const existingWindow = Object.values(useWindowStore.getState().windows).find(
            (w) => w.appId === appId
        );

        if (existingWindow) {
            if (existingWindow.isMinimized) {
                useWindowStore.getState().unminimizeWindow(existingWindow.id);
            } else {
                useWindowStore.getState().focusWindow(existingWindow.id);
            }
        } else {
            openWindow(
                appId,
                app.name,
                app.defaultWindowConfig.defaultWidth,
                app.defaultWindowConfig.defaultHeight
            );
        }
    }, [app, appId, openWindow]);

    if (!app) return null;

    return (
        <motion.div
            ref={ref}
            className="relative flex flex-col items-center cursor-pointer group"
            onClick={handleClick}
            whileTap={{ scale: 0.85 }}
            transition={{ type: "spring", stiffness: 500, damping: 30 }}
        >
            {/* Tooltip */}
            <div
                className="absolute -top-8 px-2 py-0.5 rounded-md text-[10px] font-medium
                    bg-foreground/80 text-background whitespace-nowrap
                    opacity-0 group-hover:opacity-100 transition-opacity duration-150
                    pointer-events-none"
            >
                {app.name}
            </div>

            {/* Icon */}
            <motion.div
                className="flex items-center justify-center transition-shadow duration-200"
                style={{ width: size, height: size }}
            >
                <div className="w-12 h-12 flex items-center justify-center">
                    <AppleIcon
                        {...app.iconConfig}
                        isActive={windowState.hasOpenWindow}
                        style="3d"
                    />
                </div>
            </motion.div>

            {/* Window indicator dot */}
            {windowState.hasOpenWindow && (
                <div className="absolute -bottom-1.5 flex gap-0.5">
                    <div
                        className={`w-1 h-1 rounded-full transition-colors duration-200 ${windowState.hasActive
                            ? "bg-white"
                            : windowState.hasMinimized
                                ? "bg-white/30"
                                : "bg-white/60"
                            }`}
                    />
                </div>
            )}
        </motion.div>
    );
};

// ─── Dock Component ──────────────────────────────────────────────────────────

export const Dock = () => {
    const getDockApps = useAppRegistry((s) => s.getDockApps);
    const dockApps = useMemo(() => getDockApps(), [getDockApps]);
    const mouseX = useMotionValue(-MAGNIFICATION_DISTANCE * 2);

    return (
        <motion.div
            className="absolute bottom-6 left-1/2 -translate-x-1/2"
            style={{ zIndex: Z_LAYERS.DOCK }}
            initial={{ y: 80 }}
            animate={{ y: 0 }}
            transition={{ type: "spring", stiffness: 300, damping: 30, delay: 0.2 }}
            onMouseMove={(e) => mouseX.set(e.clientX)}
            onMouseLeave={() => mouseX.set(-MAGNIFICATION_DISTANCE * 2)}
        >
            {/* Glass container */}
            <div
                className="flex items-end gap-2 px-3 pb-2 pt-2
                   bg-white/20 backdrop-blur-[40px] rounded-[24px]
                   border border-white/30 shadow-[0_20px_40px_rgba(0,0,0,0.1)]"
            >
                {dockApps.map((app, i) => (
                    <DockIcon key={app.id} appId={app.id} mouseX={mouseX} index={i} />
                ))}
            </div>
        </motion.div>
    );
};

