"use client";

import { useCallback, useEffect, useState } from "react";
import { motion } from "framer-motion";
import { Search } from "lucide-react";
import { AppleIcon } from "./AppleIcon";

import { useWindowStore } from "@/stores/useWindowStore";
import { useAppRegistry } from "@/stores/useAppRegistry";
import { useSpotlightStore } from "@/stores/useSpotlightStore";
import { Z_LAYERS } from "@/hooks/useZIndex";
import type { AppId } from "@/types/app";

// ─── Menu Bar ────────────────────────────────────────────────────────────────

const NAV_ITEMS: { label: string; appId: AppId }[] = [
    { label: "Projects", appId: "projects" },
    { label: "Archive", appId: "lab" },
    { label: "About", appId: "about" },
    { label: "Contact", appId: "contact" },
];

export const MenuBar = () => {
    const openWindow = useWindowStore((s) => s.openWindow);
    const getApp = useAppRegistry((s) => s.getApp);
    const toggleSpotlight = useSpotlightStore((s) => s.toggle);

    // Live clock
    const [time, setTime] = useState("");
    const [mounted, setMounted] = useState(false);

    useEffect(() => {
        setMounted(true);
        const updateClock = () => {
            const now = new Date();
            setTime(
                now.toLocaleTimeString("en-US", {
                    hour: "2-digit",
                    minute: "2-digit",
                    hour12: false,
                })
            );
        };
        updateClock();
        const interval = setInterval(updateClock, 10_000);
        return () => clearInterval(interval);
    }, []);

    const handleNavClick = useCallback(
        (appId: AppId) => {
            const app = getApp(appId);
            if (app) {
                openWindow(
                    appId,
                    app.name,
                    app.defaultWindowConfig.defaultWidth,
                    app.defaultWindowConfig.defaultHeight
                );
            }
        },
        [getApp, openWindow]
    );


    return (
        <motion.header
            className="absolute top-0 left-0 right-0 h-10 flex items-center justify-between px-6
                 bg-transparent backdrop-blur-sm border-b border-white/10"
            style={{ zIndex: Z_LAYERS.MENUBAR }}
            initial={{ opacity: 0, y: -10 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.5 }}
        >
            {/* ── Left: Brand ───────────────────────────────────────── */}
            <div className="flex items-center">
                <span className="text-[13px] font-semibold tracking-tight text-white/90">
                    Dzakwan
                </span>
            </div>

            {/* ── Right: Navigation & Status ──────────────────────────── */}
            <div className="flex items-center gap-6">
                <nav className="flex items-center gap-5">
                    {NAV_ITEMS.map((item) => (
                        <button
                            key={item.appId}
                            onClick={() => handleNavClick(item.appId)}
                            className="text-[12.5px] font-medium text-white/60
                         hover:text-white/90 transition-colors duration-200"
                        >
                            {item.label}
                        </button>
                    ))}
                </nav>

                <div className="flex items-center gap-3 pl-2 border-l border-white/10">
                    {/* Spotlight */}
                    <button
                        onClick={toggleSpotlight}
                        className="text-white/50 hover:text-white/80 transition-colors"
                    >
                        <AppleIcon icon={Search} style="symbol" size={14} />
                    </button>


                    {/* Clock */}
                    {mounted && (
                        <span className="text-[12px] font-semibold text-white/70 tabular-nums min-w-[36px] text-right">
                            {time}
                        </span>
                    )}
                </div>
            </div>
        </motion.header>
    );
};

"use client";

import { useWindowStore } from "@/stores/useWindowStore";
import { useZIndex, Z_LAYERS } from "@/hooks/useZIndex";
import { motion, AnimatePresence } from "framer-motion";

export const SnapOverlay = () => {
    const snapPreview = useWindowStore((s) => s.snapPreview);

    return (
        <div
            className="absolute inset-0 pointer-events-none"
            style={{ zIndex: Z_LAYERS.WINDOWS_MAX + 1 }} // Above all windows
        >
            <AnimatePresence>
                {snapPreview && (
                    <motion.div
                        initial={{ opacity: 0, scale: 0.95 }}
                        animate={{ opacity: 1, scale: 1 }}
                        exit={{ opacity: 0, scale: 0.95 }}
                        transition={{ duration: 0.15 }}
                        className="absolute bg-foreground/10 backdrop-blur-sm rounded-xl border-2 border-foreground/20"
                        style={{
                            ...(snapPreview === "left" && {
                                top: 48,
                                left: 12,
                                bottom: 84, // Dock height + padding
                                width: "48%",
                            }),
                            ...(snapPreview === "right" && {
                                top: 48,
                                right: 12,
                                bottom: 84,
                                width: "48%",
                            }),
                            ...(snapPreview === "full" && {
                                top: 48,
                                left: 12,
                                right: 12,
                                bottom: 84,
                            }),
                        }}
                    />
                )}
            </AnimatePresence>
        </div>
    );
};

"use client";

import { useEffect, useState } from "react";
import { Command } from "cmdk";
import { motion, AnimatePresence } from "framer-motion";
import {
    Search,
    AppWindow,
    Zap,
    FolderKanban,
    Command as CommandIcon,
    Terminal
} from "lucide-react";
import { useSpotlightStore } from "@/stores/useSpotlightStore";
import { useWindowStore } from "@/stores/useWindowStore";
import { useAppRegistry } from "@/stores/useAppRegistry";
import { AppleIcon } from "./AppleIcon";
import { projects } from "../apps/projects/data";

export const Spotlight = () => {
    const { isOpen, close, query, setQuery, results } = useSpotlightStore();
    const openWindow = useWindowStore((s) => s.openWindow);
    const allApps = useAppRegistry((s) => s.getAllApps());
    const apps = useAppRegistry((s) => s.apps);
    const searchableApps = allApps.filter(a => a.id !== "project-detail");

    const handleSelect = (item: any) => {
        if (item.appId) {
            const app = apps.get(item.appId);
            if (app) {
                openWindow(
                    app.id,
                    app.name,
                    app.defaultWindowConfig.defaultWidth,
                    app.defaultWindowConfig.defaultHeight,
                    item.metadata
                );
            }
        }
        close();
    };

    return (
        <AnimatePresence>
            {isOpen && (
                <div className="absolute inset-0 z-[9999] flex items-start justify-center pt-[20vh] p-4">
                    {/* Backdrop */}
                    <motion.div
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                        onClick={close}
                        className="absolute inset-0 bg-black/20 backdrop-blur-md"
                    />

                    {/* Spotlight Dialog */}
                    <motion.div
                        initial={{ opacity: 0, scale: 0.95, y: -20 }}
                        animate={{ opacity: 1, scale: 1, y: 0 }}
                        exit={{ opacity: 0, scale: 0.95, y: -20 }}
                        transition={{ type: "spring", damping: 25, stiffness: 300 }}
                        className="relative w-full max-w-2xl bg-white rounded-3xl border border-black/5 shadow-[0_20px_70px_-10px_rgba(0,0,0,0.15),0_10px_30px_-5px_rgba(0,0,0,0.1)] overflow-hidden"
                    >
                        <Command className="w-full">
                            <div className="flex items-center border-b border-border/20 px-6 py-4">
                                <Search size={20} className="text-muted-foreground mr-3" />
                                <Command.Input
                                    value={query}
                                    onValueChange={setQuery}
                                    placeholder="Search apps, projects, or commands..."
                                    className="flex-1 bg-transparent border-none outline-none text-xl font-bold tracking-tight text-black placeholder:text-black/15 py-2"
                                />
                                <div className="flex items-center gap-1.5 px-2 py-1 rounded-lg bg-muted/30 border border-border/40">
                                    <span className="text-[10px] font-black uppercase tracking-widest text-muted-foreground/60">ESC</span>
                                </div>
                            </div>

                            <Command.List className="max-h-[450px] overflow-y-auto p-4 scroll-smooth">
                                <Command.Empty className="py-12 text-center text-muted-foreground font-medium">
                                    No results found for &ldquo;{query}&rdquo;
                                </Command.Empty>

                                {/* Apps Group */}
                                <Command.Group heading="Applications" className="px-2 py-3 overflow-hidden text-black/25 text-[11px] uppercase tracking-tight font-bold">
                                    <div className="flex flex-col gap-1 mt-2">
                                        {searchableApps.map(app => (
                                            <CommandItem
                                                key={app.id}
                                                title={app.name}
                                                desc={`Open ${app.name} application`}
                                                iconConfig={app.iconConfig}
                                                onSelect={() => handleSelect({ appId: app.id })}
                                            />
                                        ))}
                                    </div>
                                </Command.Group>

                                {/* Projects Group */}
                                <Command.Group heading="Projects" className="px-2 py-3 overflow-hidden text-black/25 text-[11px] uppercase tracking-tight font-bold mt-2 border-t border-black/5">
                                    <div className="flex flex-col gap-1 mt-2">
                                        {projects.map(p => (
                                            <CommandItem
                                                key={p.id}
                                                title={p.name}
                                                desc={`${p.role} at ${p.brand}`}
                                                iconConfig={{ image: p.thumbnail }}
                                                style="photo"
                                                onSelect={() => handleSelect({ appId: "project-detail", metadata: { projectId: p.id } })}
                                            />
                                        ))}
                                    </div>
                                </Command.Group>

                                {/* Commands Group */}
                                <Command.Group heading="Commands" className="px-2 py-3 overflow-hidden text-black/25 text-[11px] uppercase tracking-tight font-bold mt-2 border-t border-black/5">
                                    <div className="flex flex-col gap-1 mt-2">
                                        <CommandItem
                                            title="Minimize All Windows"
                                            desc="Hide all open windows"
                                            iconConfig={{ icon: CommandIcon, color: "#8E8E93" }}
                                            onSelect={() => {
                                                useWindowStore.getState().minimizeAll();
                                                close();
                                            }}
                                        />
                                        <CommandItem
                                            title="Close All Windows"
                                            desc="Terminate all running applications"
                                            iconConfig={{ icon: Terminal, color: "#8E8E93" }}
                                            onSelect={() => {
                                                useWindowStore.getState().closeAll();
                                                close();
                                            }}
                                        />
                                    </div>
                                </Command.Group>
                            </Command.List>

                            {/* Footer */}
                            <div className="px-6 py-4 bg-[#F9F9FB] border-t border-black/5 flex items-center justify-between">
                                <p className="text-[10px] font-bold uppercase tracking-tight text-black/25">
                                    Spotlight Search
                                </p>
                                <div className="flex items-center gap-4">
                                    <FooterAction label="Navigate" keys={["↑", "↓"]} />
                                    <FooterAction label="Open" keys={["↵"]} />
                                </div>
                            </div>
                        </Command>
                    </motion.div>
                </div>
            )}
        </AnimatePresence>
    );
};

// ─── Sub-Components ──────────────────────────────────────────────────────────

function CommandItem({ title, desc, iconConfig, shortcut, onSelect, style }: any) {
    return (
        <Command.Item
            onSelect={onSelect}
            className="flex items-center gap-4 px-4 py-3 rounded-2xl cursor-pointer aria-selected:bg-[#FFD600] aria-selected:text-black group transition-all duration-200"
        >
            <div className="w-10 h-10 rounded-xl bg-muted group-aria-selected:bg-primary-foreground/10 flex items-center justify-center transition-colors">
                <AppleIcon {...iconConfig} style={style || "symbol"} size={18} />
            </div>
            <div className="flex-1 min-w-0">
                <p className="font-bold text-sm tracking-tight">{title}</p>
                <p className="text-xs opacity-60 truncate font-medium">{desc}</p>
            </div>
            {shortcut && (
                <div className="text-[10px] font-black tracking-widest opacity-40 group-aria-selected:opacity-80">
                    {shortcut}
                </div>
            )}
        </Command.Item>
    );
}

function FooterAction({ label, keys }: { label: string; keys: string[] }) {
    return (
        <div className="flex items-center gap-2">
            <span className="text-[10px] font-bold text-black/40 uppercase tracking-tight">{label}</span>
            <div className="flex gap-1">
                {keys.map(k => (
                    <div key={k} className="w-5 h-5 rounded-md bg-white border border-black/5 flex items-center justify-center text-[10px] font-bold text-black shadow-sm">
                        {k}
                    </div>
                ))}
            </div>
        </div>
    );
}

"use client";

import { useCallback, Suspense } from "react";
import { Rnd } from "react-rnd";
import { motion } from "framer-motion";

import { useWindowStore } from "@/stores/useWindowStore";
import { useAppRegistry } from "@/stores/useAppRegistry";
import { useZIndex } from "@/hooks/useZIndex";
import { useWindowSnap } from "@/hooks/useWindowSnap";
import { WindowControls } from "./WindowControls";
import { WindowContext } from "./WindowContext";
import type { WindowId } from "@/types/window";
import type { AppId } from "@/types/app";
import { useState, type ReactNode } from "react";

// ─── Props ───────────────────────────────────────────────────────────────────

interface WindowProps {
    windowId: WindowId;
}

// ─── Component ───────────────────────────────────────────────────────────────

export const Window = ({ windowId }: WindowProps) => {
    const win = useWindowStore((s) => s.windows[windowId]);
    const focusWindow = useWindowStore((s) => s.focusWindow);
    const moveWindow = useWindowStore((s) => s.moveWindow);
    const resizeWindow = useWindowStore((s) => s.resizeWindow);
    const maximizeWindow = useWindowStore((s) => s.maximizeWindow);
    const restoreWindow = useWindowStore((s) => s.restoreWindow);

    const getApp = useAppRegistry((s) => s.getApp);
    const { getWindowZIndex } = useZIndex();
    const { handleDrag, handleDragStop } = useWindowSnap(windowId);

    const [headerActions, setHeaderActions] = useState<ReactNode>(null);

    if (!win) return null;

    const app = getApp(win.appId as AppId);
    if (!app) return null;

    const AppComponent = app.component;
    const config = app.defaultWindowConfig;

    const handleFocus = () => {
        focusWindow(windowId);
    };

    const handleDoubleClickTitle = () => {
        if (win.isMaximized) {
            restoreWindow(windowId);
        } else {
            maximizeWindow(windowId);
        }
    };

    return (
        <WindowContext.Provider value={{ setHeaderActions, metadata: win.metadata }}>
            <motion.div
                initial={{ opacity: 0, scale: 0.95 }}
                animate={{ opacity: 1, scale: 1 }}
                exit={{ opacity: 0, scale: 0.95 }}
                transition={{ duration: 0.2, ease: "easeOut" }}
                style={{
                    position: "absolute",
                    top: 0,
                    left: 0,
                    width: "100%",
                    height: "100%",
                    zIndex: getWindowZIndex(win.zIndex),
                    pointerEvents: "none",
                }}
            >
                <Rnd
                    position={{ x: win.position.x, y: win.position.y }}
                    size={{ width: win.size.w, height: win.size.h }}
                    minWidth={config.minWidth}
                    minHeight={config.minHeight}
                    maxWidth={config.maxWidth}
                    maxHeight={config.maxHeight}
                    dragHandleClassName="window-drag-handle"
                    enableResizing={config.resizable && !win.isMaximized}
                    disableDragging={!config.draggable || win.isMaximized}
                    bounds="parent"
                    style={{
                        pointerEvents: "auto",
                    }}
                    onMouseDown={handleFocus}
                    onDrag={handleDrag}
                    onDragStop={(_e: any, d: any) => {
                        moveWindow(windowId, { x: d.x, y: d.y });
                        handleDragStop();
                    }}
                    onResizeStop={(_e: any, _dir: any, ref: any, _delta: any, position: any) => {
                        resizeWindow(windowId, {
                            w: parseInt(ref.style.width, 10),
                            h: parseInt(ref.style.height, 10),
                        });
                        moveWindow(windowId, { x: position.x, y: position.y });
                    }}
                    className={`
                    rounded-[16px] overflow-hidden flex flex-col
                    border border-border/40
                    bg-card
                    transition-all duration-300
                    ${win.isFocused
                            ? "shadow-os-window scale-[1.002]"
                            : "shadow-os-medium opacity-90 scale-100"
                        }
                `}
                    resizeHandleStyles={{
                        top: { cursor: "n-resize" },
                        right: { cursor: "e-resize" },
                        bottom: { cursor: "s-resize" },
                        left: { cursor: "w-resize" },
                        topRight: { cursor: "ne-resize" },
                        topLeft: { cursor: "nw-resize" },
                        bottomRight: { cursor: "se-resize" },
                        bottomLeft: { cursor: "sw-resize" },
                    }}
                >
                    {/* Inner flex wrapper – needed because react-rnd's internal div breaks the flex chain */}
                    <div className="flex flex-col h-full w-full">
                        {/* ── Title Bar ───────────────────────────────────────────────── */}
                        {!config.hideTitleBar && (
                            <div
                                className="window-drag-handle cursor-grab active:cursor-grabbing"
                                onDoubleClick={handleDoubleClickTitle}
                            >
                                <WindowControls
                                    windowId={windowId}
                                    title={win.title}
                                    isMaximized={win.isMaximized}
                                    headerActions={headerActions}
                                />
                            </div>
                        )}

                        {/* ── Content Area ────────────────────────────────────────────── */}
                        <div className="flex-1 min-h-0 overflow-auto">
                            <Suspense
                                fallback={
                                    <div className="flex items-center justify-center h-full text-muted-foreground text-sm">
                                        Loading...
                                    </div>
                                }
                            >
                                <AppComponent />
                            </Suspense>
                        </div>
                    </div>
                </Rnd>
            </motion.div>
        </WindowContext.Provider>
    );
};

